public class ShortCircuit {
    static int count = 0;
    static boolean check(boolean val) {
        count++;
        return val;
    }
    public static void main(String[] args) {
        boolean r1 = check(false) && check(true);
        System.out.println(r1 + " " + count);
        boolean r2 = check(true) || check(false);
        System.out.println(r2 + " " + count);
    }
}
